1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<[number, number]> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [0, -1],           [0, 1],
6	  [1, -1],  [1, 0],  [1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const neighborsOf = ([x, y]: Cell): Cell[] =>
12	  NEIGHBOR_OFFSETS.map(([dx, dy]) => [x + dx, y + dy]);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const liveKeys = new Set(cells.map(cellKey));
16	  const isLive = (cell: Cell): boolean => liveKeys.has(cellKey(cell));
17	  const countLiveNeighbors = (cell: Cell): number =>
18	    neighborsOf(cell).filter(isLive).length;
19	
20	  const survivors = cells.filter((cell) => {
21	    const count = countLiveNeighbors(cell);
22	    return count === 2 || count === 3;
23	  });
24	
25	  const deadNeighbors = new Map<string, Cell>();
26	  for (const cell of cells) {
27	    for (const neighbor of neighborsOf(cell)) {
28	      if (!isLive(neighbor)) {
29	        deadNeighbors.set(cellKey(neighbor), neighbor);
30	      }
31	    }
32	  }
33	  const births = [...deadNeighbors.values()].filter(
34	    (cell) => countLiveNeighbors(cell) === 3,
35	  );
36	
37	  return [...survivors, ...births];
38	}
