1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Horizontal line of 3: center (1,0) has 2 neighbors → survives
16	    const result = nextGeneration([[0, 0], [1, 0], [2, 0]]);
17	    expect(result).toContainEqual([1, 0]);
18	  });
19	  it("keeps a live cell alive when it has 3 live neighbors (survival)", () => {
20	    // T-shape: cell (1,0) has 3 neighbors (0,0), (2,0), (1,1)
21	    const result = nextGeneration([[0, 0], [1, 0], [2, 0], [1, 1]]);
22	    expect(result).toContainEqual([1, 0]);
23	  });
24	  it("kills a live cell with more than 3 live neighbors (overpopulation)", () => {
25	    // Center (1,1) has 4 diagonal neighbors → dies
26	    const result = nextGeneration([[1, 1], [0, 0], [2, 0], [0, 2], [2, 2]]);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("brings a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
30	    // L-shape: dead cell (1,1) has 3 live neighbors → becomes alive
31	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("oscillates a vertical blinker into a horizontal blinker", () => {
35	    const result = nextGeneration([[0, 0], [0, 1], [0, 2]]);
36	    expect(result).toHaveLength(3);
37	    expect(result).toContainEqual([-1, 1]);
38	    expect(result).toContainEqual([0, 1]);
39	    expect(result).toContainEqual([1, 1]);
40	  });
41	  it("preserves a 2x2 block (still life)", () => {
42	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
43	    expect(result).toHaveLength(4);
44	    expect(result).toContainEqual([0, 0]);
45	    expect(result).toContainEqual([1, 0]);
46	    expect(result).toContainEqual([0, 1]);
47	    expect(result).toContainEqual([1, 1]);
48	  });
49	  it("handles negative coordinates correctly", () => {
50	    // Vertical blinker at negative coordinates
51	    const result = nextGeneration([[-5, -5], [-5, -4], [-5, -3]]);
52	    expect(result).toHaveLength(3);
53	    expect(result).toContainEqual([-6, -4]);
54	    expect(result).toContainEqual([-5, -4]);
55	    expect(result).toContainEqual([-4, -4]);
56	  });
57	});
